1	export type Cell = [number, number];
2	
3	const isNeighbor = (cell: Cell, other: Cell): boolean => {
4	  const [x, y] = cell;
5	  const [ox, oy] = other;
6	  const sameCell = ox === x && oy === y;
7	  return !sameCell && Math.abs(ox - x) <= 1 && Math.abs(oy - y) <= 1;
8	};
9	
10	const countLiveNeighbors = (cell: Cell, cells: Cell[]): number =>
11	  cells.filter((other) => isNeighbor(cell, other)).length;
12	
13	const deadNeighborCandidates = (cells: Cell[]): Cell[] => {
14	  const candidates: Cell[] = [];
15	  const seen = new Set<string>();
16	  const isLive = new Set(cells.map(([x, y]) => `${x},${y}`));
17	  for (const [x, y] of cells) {
18	    for (let dx = -1; dx <= 1; dx++) {
19	      for (let dy = -1; dy <= 1; dy++) {
20	        if (dx === 0 && dy === 0) continue;
21	        const nx = x + dx;
22	        const ny = y + dy;
23	        const key = `${nx},${ny}`;
24	        if (isLive.has(key)) continue;
25	        if (seen.has(key)) continue;
26	        seen.add(key);
27	        candidates.push([nx, ny]);
28	      }
29	    }
30	  }
31	  return candidates;
32	};
33	
34	export const nextGeneration = (cells: Cell[]): Cell[] => {
35	  const survivors = cells.filter((cell) => countLiveNeighbors(cell, cells) === 2);
36	  const births = deadNeighborCandidates(cells).filter(
37	    (cell) => countLiveNeighbors(cell, cells) === 3
38	  );
39	  return [...survivors, ...births];
40	};
41

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("returns empty for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("a single live cell dies (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent live cells both die (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("a live cell with 2 live neighbors survives", () => {
15	    // Blinker: vertical column. Center (0,1) has 2 live neighbors and survives.
16	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
17	    expect(result).toContainEqual([0, 1]);
18	  });
19	  it("a live cell with more than 3 live neighbors dies (overpopulation)", () => {
20	    // Center (1,1) has 4 live neighbors (the 4 corners), should die.
21	    const result = nextGeneration([[0, 0], [2, 0], [1, 1], [0, 2], [2, 2]]);
22	    expect(result).not.toContainEqual([1, 1]);
23	  });
24	  it("a dead cell with exactly 3 live neighbors becomes alive (reproduction)", () => {
25	    // Cells form an L; dead cell (1,1) has exactly 3 live neighbors (0,0), (1,0), (0,1).
26	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
27	    expect(result).toContainEqual([1, 1]);
28	  });
